import sys, tinytuya, json

DEVICE_ID = 'ebb508d08d4b6d9050vjjr'
IP = '192.168.1.177'
LOCAL_KEY = 'qCJtqpW+IuC+0Y&R'

CODES = {
    'on':  '',
    'off': '',
}

action = sys.argv[1] if len(sys.argv) > 1 else 'on'
code = CODES.get(action)
if not code:
    print('unknown action')
    sys.exit(1)

d = tinytuya.Device(DEVICE_ID, IP, LOCAL_KEY, version=3.3)
payload = json.dumps({'control': 'send_ir', 'type': 0, 'head': '', 'key1': '1' + code})
result = d.set_value(201, payload)
print(f'sent {action}: {result}')
